const centerAlignStyle = {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
};

export const Timeline = () => {

    return (
        <div className="wrapper">
            {sampleData.map((item, i) => (
                <Accordion key={i} className="blog-content">
                    <AccordionSummary  expandIcon={<ExpandMoreIcon />} style={centerAlignStyle}>
                        <Typography>{item.title}</Typography>
                    </AccordionSummary>
                    <AccordionDetails>
                        <Typography><strong>Author:</strong> {item.author}</Typography>
                        <Typography><strong>Date:</strong> {item.date}</Typography>
                        <Typography><strong></strong> {item.content}</Typography>
                    </AccordionDetails>
                </Accordion>
            ))};
        </div>
    )
}

